/**
 * Format a display name as "Firstname L." — proper-cased with last-name initial.
 */
function hone_format_reviewer_name($raw_name) {
    $raw_name = trim($raw_name);
    if ($raw_name === '') {
        return '';
    }

    $parts = preg_split('/\s+/', $raw_name);
    $parts = array_map(function ($p) {
        return ucfirst(mb_strtolower($p));
    }, $parts);

    if (count($parts) === 1) {
        return $parts[0];
    }

    $first = $parts[0];
    $last_part = end($parts);
    $last_initial = mb_strtoupper(mb_substr($last_part, 0, 1));

    return $first . ' ' . $last_initial . '.';
}

/**
 * Convert a review title to sentence case.
 */
function hone_sentence_case($text) {
    $text = trim($text);
    if ($text === '') {
        return '';
    }
    return ucfirst(mb_strtolower($text));
}

/**
 * Fetch recent Trustpilot reviews via the public Business Units API.
 * Results are cached for 1 hour using WordPress transients.
 *
 * Titles are converted to sentence case and names to "Firstname L." format.
 * Reviews with titles exceeding word/character limits are excluded.
 *
 * @param int $count     Number of reviews to request from the API (max 20).
 * @param int $min_stars Minimum star rating to include (default 4).
 * @return array|false   Array of ['quote' => string, 'reviewer' => string] or false on failure.
 */
function hone_get_trustpilot_reviews($count = 20, $min_stars = 5) {
    $transient_key = 'hone_trustpilot_reviews_' . $count . '_' . $min_stars;
    $cached = get_transient($transient_key);
    if ($cached !== false) {
        return $cached;
    }

    if (!function_exists('get_field')) {
        return false;
    }

    $trustpilot_api = get_field('trustpilot_api', 'option');

