.boost-your-testosterone.hero {
	background-color: colors.$color-white;
	padding: fonts.rem(40px) fonts.rem(64px);
	@media #{layout.$medium-screen-and-smaller} {
		padding: fonts.rem(16px) fonts.rem(32px) fonts.rem(40px);
		flex-direction: column;
		gap: fonts.rem(24px);
	}
	@media #{layout.$small-screen-only} {
		padding-inline: fonts.rem(16px);
	}

	.container.grid {
		gap: fonts.rem(64px);
		grid-template-columns: 600px 1fr;
		@media #{layout.$medium-screen-and-smaller} {
			grid-template-columns: 1fr;
			gap: fonts.rem(24px);
		}
	}

	.container {
		@media #{layout.$medium-screen-and-smaller} {
			display: flex;
			flex-direction: column;
			gap: fonts.rem(24px);
		}
	}

	// Left column — image
	.media-wrapper {
		padding: 0;
		display: flex;
		align-items: center;
		background-color: colors.$color-white;
		@media #{layout.$medium-screen-and-smaller} {
			order: 1;
		}

		.media-block {
			width: 600px;
			aspect-ratio: 1 / 1;
			@media #{layout.$medium-screen-and-smaller} {
				width: 100%;
				max-width: fonts.rem(600px);
				height: auto;
				margin-left: auto;
				margin-right: auto;
			}

			video {
				width: 100%;
				height: 100%;
				object-fit: cover;
			}
		}
	}

	// Right column — content
	.content-wrapper {
		padding: 0;
		display: flex;
		flex-direction: column;
		justify-content: center;
		gap: fonts.rem(40px);
		@media #{layout.$medium-screen-and-smaller} {
			order: 2;
			gap: fonts.rem(24px);
		}

