/**
 * Mens HRT Enhanced PDP 1
 * Page-specific JavaScript for page-mens-hrt-enhanced-pdp-1.php
 * 
 * Autoplay first video when the section scrolls into view
 */

// Import utilities
import { initCarousel } from '../utilities/carousel.js';

// Export to window for global access
window.initCarousel = initCarousel;

/**
 * How It Works — click-to-play video cards
 * - Thumbnail shows by default as placeholder
 * - On click: lazy-load video src, play, hide thumbnail
 * - Clicking a playing video pauses it
 * - Only one video plays at a time
 */
function initSocialVideos() {
	const items = document.querySelectorAll('.how-it-works.social-videos .review-video-item');
	const loadedMap = new WeakMap();

	function loadAndPlay(item) {
		const video = item.querySelector('video');
		if (!video) return;

		items.forEach((other) => {
			if (other !== item) stopVideo(other);
		});

		if (!loadedMap.get(video)) {
			const lazySrc = video.getAttribute('data-src');
			if (!lazySrc) return;
			video.src = lazySrc;
			video.load();
			loadedMap.set(video, true);
		}

		video.play().then(() => {
			item.classList.add('playing');
		}).catch(() => {});
	}

	function stopVideo(item) {
		const video = item.querySelector('video');
		if (!video) return;
		video.pause();
		item.classList.remove('playing');
	}

	items.forEach((item) => {
		const video = item.querySelector('video');
		const muteBtn = item.querySelector('.mute-toggle');
		if (!video) return;

		item.addEventListener('click', () => {
			if (item.classList.contains('playing')) {
				stopVideo(item);
			} else {
				loadAndPlay(item);
			}
		});

		if (muteBtn) {
			muteBtn.addEventListener('click', (e) => {
				e.stopPropagation();
				const shouldUnmute = video.muted;

				if (shouldUnmute) {
					items.forEach((other) => {
						const otherVideo = other.querySelector('video');
						if (otherVideo && otherVideo !== video) {
							otherVideo.muted = true;
							other.classList.remove('unmuted');
							const otherBtn = other.querySelector('.mute-toggle');
							if (otherBtn) otherBtn.setAttribute('aria-label', 'Unmute video');
						}
					});
				}

				video.muted = !shouldUnmute;
				item.classList.toggle('unmuted', shouldUnmute);
				muteBtn.setAttribute('aria-label', shouldUnmute ? 'Mute video' : 'Unmute video');
			});
		}
	});

	// Autoplay first video when the section scrolls into view
	const firstItem = items[0];
	if (firstItem) {
		const observer = new IntersectionObserver((entries) => {
			entries.forEach((entry) => {
				if (entry.isIntersecting) {
					loadAndPlay(firstItem);
					observer.disconnect();
				}
			});
		}, { threshold: 0.3 });

		observer.observe(firstItem);
	}
}

jQuery(document).ready(function($) {		
	// Testimonials carousel
	const testimonialsParams = {
		slidesToShow: 3,
		infinite: true,
		centerMode: true,
		responsive: [
			{
				breakpoint: 1024,
				settings: {
					slidesToShow: 1,
					centerPadding: '8rem',
				}
			},
			{
				breakpoint: 600,
				settings: {
					slidesToShow: 1,
					centerPadding: '1rem',
				}
			}
		]
	};
	initCarousel(testimonialsParams, '.testimonials');

	// Injections gallery — native scroll carousel + clickable thumbnail nav (tablet/mobile)
	const mainCarousel = document.querySelector('.injections-main-carousel');
	if (mainCarousel) {
		const slides = mainCarousel.querySelectorAll('.slide');
		const thumbs = document.querySelectorAll('.injections-thumbs .thumb');

		function getSlideByIndex(idx) {
			return mainCarousel.querySelector('.slide[data-slide="' + idx + '"]');
		}

		function updateActiveThumb(dataIndex) {
			thumbs.forEach(t => t.classList.remove('active'));
			const match = document.querySelector('.injections-thumbs .thumb[data-slide="' + dataIndex + '"]');
			if (match) match.classList.add('active');
		}

		function scrollToSlide(slide) {
			mainCarousel.style.scrollSnapType = '';
			mainCarousel.scrollTo({ left: slide.offsetLeft, behavior: 'smooth' });
		}

		thumbs.forEach(thumb => {
			thumb.addEventListener('click', () => {
				const index = parseInt(thumb.dataset.slide, 10);
				const slide = getSlideByIndex(index);
				if (slide) {
					updateActiveThumb(index);
					scrollToSlide(slide);
				}
			});
		});

		let scrollTimeout;
		mainCarousel.addEventListener('scroll', () => {
			clearTimeout(scrollTimeout);
			scrollTimeout = setTimeout(() => {
				const scrollLeft = mainCarousel.scrollLeft;
				let closestSlide = slides[0];
				let closestDist = Infinity;
				slides.forEach(slide => {
					const dist = Math.abs(slide.offsetLeft - scrollLeft);
					if (dist < closestDist) {
						closestDist = dist;
						closestSlide = slide;
					}
				});
				updateActiveThumb(parseInt(closestSlide.dataset.slide, 10));
			}, 50);
		});

		// Mouse drag-to-scroll
		let isDragging = false;
		let startX = 0;
		let scrollStart = 0;

		mainCarousel.addEventListener('mousedown', (e) => {
			isDragging = true;
			startX = e.pageX;
			scrollStart = mainCarousel.scrollLeft;
			mainCarousel.style.cursor = 'grabbing';
			mainCarousel.style.scrollSnapType = 'none';
			e.preventDefault();
		});

		window.addEventListener('mousemove', (e) => {
			if (!isDragging) return;
			const dx = e.pageX - startX;
			mainCarousel.scrollLeft = scrollStart - dx;
		});

		window.addEventListener('mouseup', () => {
			if (!isDragging) return;
			isDragging = false;
			mainCarousel.style.cursor = '';
			mainCarousel.style.scrollSnapType = '';
		});

		updateActiveThumb(0);
	}
});

/**
 * Benefits Timeline — click-to-expand cards
 * Like https://get.timeline.com/meta/gummies .framer-wd2b1m
 * - First card starts active (expanded with full text)
 * - Clicking a card makes it active, others collapse
 * - Active: wider, full opacity, shows heading + body
 * - Inactive: narrower, 0.8 opacity, only shows day label
 */
function initBenefitsTimeline() {
	const cards = document.querySelectorAll('.benefits-timeline .timeline-card');
	if (!cards.length) return;

	// Set first card as active by default
	cards[0].classList.add('active');

	cards.forEach((card) => {
		card.addEventListener('click', () => {
			// Remove active from all cards
			cards.forEach((c) => c.classList.remove('active'));
			// Set clicked card as active
			card.classList.add('active');
		});
	});
}

/**
 * FAQ Accordion
 * - Click header to toggle open/close
 * - Only one item open at a time (optional, currently allows multiple)
 */
function initFaqAccordion() {
	const items = document.querySelectorAll('.faq-block .faq-item');
	if (!items.length) return;

	items.forEach((item) => {
		const header = item.querySelector('.faq-header');
		if (!header) return;

		header.addEventListener('click', () => {
			const isOpen = item.classList.contains('open');

			// Close all other items
			items.forEach((other) => other.classList.remove('open'));

			// Toggle clicked item
			if (!isOpen) {
				item.classList.add('open');
				header.setAttribute('aria-expanded', 'true');
			} else {
				header.setAttribute('aria-expanded', 'false');
			}
		});
	});
}

document.addEventListener('DOMContentLoaded', () => {
	initSocialVideos();
	initBenefitsTimeline();
	initFaqAccordion();
});

