			{
				breakpoint: 1024,
				settings: {
					slidesToShow: 1,
					centerPadding: '8rem',
				}
			},
			{
				breakpoint: 600,
				settings: {
					slidesToShow: 1,
					centerPadding: '1rem',
				}
			}
		]
	};
	initCarousel(testimonialsParams, '.testimonials');

	// Injections gallery — native scroll carousel + clickable thumbnail nav (tablet/mobile)
	const mainCarousel = document.querySelector('.injections-main-carousel');
	if (mainCarousel) {
		const slides = mainCarousel.querySelectorAll('.slide');
		const thumbs = document.querySelectorAll('.injections-thumbs .thumb');

		function getSlideByIndex(idx) {
			return mainCarousel.querySelector('.slide[data-slide="' + idx + '"]');
		}

		function updateActiveThumb(dataIndex) {
			thumbs.forEach(t => t.classList.remove('active'));
			const match = document.querySelector('.injections-thumbs .thumb[data-slide="' + dataIndex + '"]');
			if (match) match.classList.add('active');
		}

		function scrollToSlide(slide) {
			mainCarousel.style.scrollSnapType = '';
			mainCarousel.scrollTo({ left: slide.offsetLeft, behavior: 'smooth' });
		}

		thumbs.forEach(thumb => {
			thumb.addEventListener('click', () => {
				const index = parseInt(thumb.dataset.slide, 10);
				const slide = getSlideByIndex(index);
				if (slide) {
					updateActiveThumb(index);
					scrollToSlide(slide);
				}
			});
		});

		let scrollTimeout;
		mainCarousel.addEventListener('scroll', () => {
			clearTimeout(scrollTimeout);
			scrollTimeout = setTimeout(() => {
				const scrollLeft = mainCarousel.scrollLeft;
				let closestSlide = slides[0];
				let closestDist = Infinity;
				slides.forEach(slide => {
					const dist = Math.abs(slide.offsetLeft - scrollLeft);
					if (dist < closestDist) {
						closestDist = dist;
						closestSlide = slide;
					}
				});
				updateActiveThumb(parseInt(closestSlide.dataset.slide, 10));
			}, 50);
		});

		// Mouse drag-to-scroll
		let isDragging = false;
		let startX = 0;
		let scrollStart = 0;

		mainCarousel.addEventListener('mousedown', (e) => {
			isDragging = true;
			startX = e.pageX;
			scrollStart = mainCarousel.scrollLeft;
			mainCarousel.style.cursor = 'grabbing';
			mainCarousel.style.scrollSnapType = 'none';
			e.preventDefault();
		});

		window.addEventListener('mousemove', (e) => {
			if (!isDragging) return;
			const dx = e.pageX - startX;
			mainCarousel.scrollLeft = scrollStart - dx;
		});

		window.addEventListener('mouseup', () => {
			if (!isDragging) return;
			isDragging = false;
			mainCarousel.style.cursor = '';
			mainCarousel.style.scrollSnapType = '';
		});

		updateActiveThumb(0);
	}
});

